# Requestをfastapiからインポートします
from fastapi import APIRouter, Depends, HTTPException, status, Request
from fastapi.responses import RedirectResponse
from authlib.integrations.starlette_client import OAuth
from jose import JWTError, jwt
from sqlalchemy.orm import Session
from . import crud, models, schemas, database
from .config import settings
import datetime
# import requests # Codexが追加したかもしれませんが、このファイルでは不要なので消しておきましょう

router = APIRouter(
    prefix="/api/v1/auth",
    tags=["auth"],
)

oauth = OAuth()
oauth.register(
    name='google',
    client_id=settings.google_client_id,
    client_secret=settings.google_client_secret,
    server_metadata_url='https://accounts.google.com/.well-known/openid-configuration',
    client_kwargs={
        'scope': 'openid email profile'
    }
)

# JWT settings
SECRET_KEY = "your-super-secret-key"  # 本番環境では必ず複雑な秘密鍵に変更してください！
ALGORITHM = "HS256"
ACCESS_TOKEN_EXPIRE_MINUTES = 30

def create_access_token(data: dict):
    to_encode = data.copy()
    expire = datetime.datetime.utcnow() + datetime.timedelta(minutes=ACCESS_TOKEN_EXPIRE_MINUTES)
    to_encode.update({"exp": expire})
    encoded_jwt = jwt.encode(to_encode, SECRET_KEY, algorithm=ALGORITHM)
    return encoded_jwt

@router.get('/login/google')
async def login_google(request: Request):
    # URLを、Googleに登録したものと一字一句同じものを直接書き込む！
    redirect_uri = 'http://localhost:8000/api/v1/auth/google/callback' 
    return await oauth.google.authorize_redirect(request, redirect_uri)

@router.get('/google/callback')
# こちらのrequestの型も「Request」として指定します
async def auth_google_callback(request: Request, db: Session = Depends(database.get_db)):
    try:
        token = await oauth.google.authorize_access_token(request)
    except Exception as e:
        raise HTTPException(status_code=status.HTTP_401_UNAUTHORIZED, detail="Could not validate credentials")

    user_info = token.get('userinfo')
    if not user_info:
        raise HTTPException(status_code=status.HTTP_401_UNAUTHORIZED, detail="Could not fetch user info")

    email = user_info.get('email')
    db_user = crud.get_user_by_email(db, email=email)

    if not db_user:
        user_create = schemas.UserCreate(email=email, name=user_info.get('name'))
        db_user = crud.create_user(db=db, user=user_create)

    access_token = create_access_token(data={"sub": db_user.email})

    response = RedirectResponse(url=f"http://localhost:3000/auth/callback?token={access_token}")
    return response